/**
 * Returns all AT scene + mesh params for a given scene slug.
 * Falls back to all params if scene is "all" or unknown.
 */
export function getSceneLayout(scene: string): SceneLayoutParams {
  const index = SCENE_INDEX[scene];
  if (!index) {
    return { scene: SCENE_PARAMS, mesh: MESH_PARAMS };
  }
  const filteredScene: Record<string, ATParamValue> = {};
  for (const k of index.sceneKeys) filteredScene[k] = SCENE_PARAMS[k];
  const filteredMesh: Record<string, ATParamValue> = {};
  for (const k of index.meshKeys) filteredMesh[k] = MESH_PARAMS[k];
  return { scene: filteredScene, mesh: filteredMesh };
}

